import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/installer-screen.Db0E_BrK.js";import{t as a}from"./chunks/launcher-screen.B4Y3DSWp.js";import{t as o}from"./chunks/macos-downloads.DCRwPSpe.js";const s=JSON.parse(`{"title":"Installing Fabric","description":"A step by step guide on how to install Fabric.","frontmatter":{"title":"Installing Fabric","description":"A step by step guide on how to install Fabric.","authors":["IMB11","Benonardo","modmuss50"],"search":false,"files":[]},"headers":[],"relativePath":"1.21.1/players/installing-fabric.md","filePath":"versions/1.21.1/players/installing-fabric.md","lastUpdated":1761424914000}`);var c={name:`1.21.1/players/installing-fabric.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Installing Fabric <a class="header-anchor" href="#h1" aria-label="Permalink to “Installing Fabric”">​</a></h1><p>This guide only applies for the official Minecraft Launcher. For third party launchers, you should consult their documentation.</p><h2 id="1-download-the-fabric-installer" tabindex="-1">1. Download the Fabric Installer <a class="header-anchor" href="#1-download-the-fabric-installer" aria-label="Permalink to “1. Download the Fabric Installer”">​</a></h2><p>You can download the Fabric Installer from the <a href="https://fabricmc.net/use/" target="_blank" rel="noreferrer">Fabric Website</a>.</p><p>If you use Windows, download the <code>.exe</code> version (<code>Download For Windows</code>), because it doesn&#39;t require Java to be installed on your system. It instead uses Java that came with the official launcher.</p><p>For macOS and Linux, you should download the <code>.jar</code> version. Sometimes, you need to install Java before this step.</p><h2 id="2-run-the-fabric-installer" tabindex="-1">2. Run the Fabric Installer <a class="header-anchor" href="#2-run-the-fabric-installer" aria-label="Permalink to “2. Run the Fabric Installer”">​</a></h2><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Close Minecraft and the Minecraft Launcher first before running the installer.</p></div><details class="details custom-block"><summary>Information for macOS users</summary><p>On macOS, you may need to right click the <code>.jar</code> file in your downloads directory and click <code>Open</code> to run it.</p><p><img src="/assets/players/installing-fabric/macos-downloads.png" alt="MacOS context menu on Fabric Installer" loading="lazy"></p><p>When asked &quot;Are you sure you want to open it?&quot;, click <code>Open</code> again.</p></details><p>Once you&#39;ve opened the installer, you should see a screen like this:</p><p><img src="/assets/players/installing-fabric/installer-screen.png" alt="Fabric Installer with &quot;Install&quot; highlighted" loading="lazy"></p><p>To install Fabric, simply choose your game version from the dropdown, and click <code>Install</code>.</p><div class="warning custom-block"><p class="custom-block-title">IMPORTANT</p><p>Make sure that &#39;Create Profile&#39; is checked.</p></div><h2 id="3-you-re-done" tabindex="-1">3. You&#39;re Done! <a class="header-anchor" href="#3-you-re-done" aria-label="Permalink to “3. You&#39;re Done!”">​</a></h2><p>Once the installer has finished, you can open the Minecraft Launcher and select the Fabric profile from the dropdown in the bottom left corner and press Play!</p><p><img src="/assets/players/installing-fabric/launcher-screen.png" alt="Minecraft Launcher with Fabric profile selected" loading="lazy"></p><p>Now that you&#39;ve installed Fabric, you can add mods to your game! Check out the <a href="./finding-mods">Finding Trustworthy Mods</a> guide for more information.</p><p>If you encounter any issues while following this guide, you can ask for help in the <a href="https://discord.gg/v6v4pMv" target="_blank" rel="noreferrer">Fabric Discord</a> in the <code>#player-support</code> channel.</p>`,18)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};